/* ——— real-footage card ——— */
function Footage({ piece, playing = true, small = false }) {
  const [wi, setWi] = useState(0);
  useEffect(() => {
    if (!playing) return;
    const t = setInterval(() => setWi((i) => (i + 1) % piece.words.length), 620);
    return () => clearInterval(t);
  }, [playing, piece.id]);
  return (
    <div className="relative w-full h-full overflow-hidden select-none" style={{ background: "#0D0C0A" }}>
      <img
        src={IMGS[piece.img]}
        alt=""
        draggable={false}
        className="absolute inset-0 w-full h-full"
        style={{ objectFit: "cover" }}
      />
      <div
        className="absolute inset-x-0 bottom-0"
        style={{ height: "45%", background: "linear-gradient(to top, rgba(0,0,0,0.55), transparent)" }}
      />
      {!small && (
        <div className="absolute inset-x-0 flex items-center justify-center px-4" style={{ bottom: "26%" }}>
          <span
            style={{
              fontFamily: SYS, fontWeight: 800, fontSize: 26, lineHeight: 1.1, color: "#fff",
              textAlign: "center", textShadow: "0 2px 14px rgba(0,0,0,0.65)", letterSpacing: "-0.01em",
            }}
          >
            {piece.words[wi]}
          </span>
        </div>
      )}
      <div className="absolute flex items-center" style={{ top: small ? 6 : 12, left: small ? 6 : 12, gap: 5 }}>
        <span
          style={{
            fontFamily: SYS, fontSize: small ? 8 : 10, fontWeight: 700, letterSpacing: "0.08em",
            color: "#fff", background: TYPE_COLORS[piece.type] || "#555", borderRadius: 999,
            padding: small ? "2px 6px" : "3px 9px", textTransform: "uppercase",
          }}
        >
          {small ? piece.kind : piece.type}
        </span>
      </div>
      <div className="absolute" style={{ top: small ? 6 : 12, right: small ? 6 : 12 }}>
        <span
          style={{
            fontFamily: "ui-monospace, Menlo, monospace", fontSize: small ? 8 : 10,
            color: "rgba(255,255,255,0.9)", background: "rgba(0,0,0,0.4)", borderRadius: 6, padding: "2px 6px",
          }}
        >
          {piece.dur}
        </span>
      </div>
    </div>
  );
}

