/* ——— SHELL ——— */
export default function SidelinePrototypeV3() {
  const [phase, setPhase] = useState("onboarding");
  const [coachName, setCoachName] = useState("Coach");
  const [mission, setMission] = useState("Fill the fall program");
  const [accent, setAccent] = useState(ACCENTS[0]);
  const [tab, setTab] = useState("today");
  const [flow, setFlow] = useState(null);
  const [pieces, setPieces] = useState(PIECES.map((p) => ({ ...p, status: "ready" })));

  const decide = (id, status, reason) =>
    setPieces((ps) => ps.map((p) => (p.id === id ? { ...p, status, reason } : p)));
  const readyCount = pieces.filter((p) => p.status === "ready").length;

  let screen;
  if (phase === "onboarding")
    screen = (
      <Onboarding
        accent={accent}
        setAccent={setAccent}
        onFinish={({ name, mission: m }) => { setCoachName(name); if (m) setMission(m); setPhase("app"); setFlow("picker"); }}
      />
    );
  else if (flow === "picker") screen = <Picker onBack={() => setFlow(null)} onSend={() => setFlow("processing")} accent={accent} />;
  else if (flow === "processing") screen = <Processing onDone={() => { setFlow(null); setTab("review"); }} accent={accent} />;
  else if (tab === "today") screen = <Today pieces={pieces} onUpload={() => setFlow("picker")} goReview={() => setTab("review")} name={coachName} accent={accent} mission={mission} setMission={setMission} />;
  else if (tab === "review") screen = <Review pieces={pieces} onDecision={decide} goToday={() => setTab("today")} accent={accent} />;
  else screen = <Business accent={accent} mission={mission} />;

  return (
    <div
      className="min-h-screen w-full flex flex-col items-center justify-center"
      style={{ background: "linear-gradient(160deg, #EAE7E1, #DAD6CE)", padding: "24px 12px" }}
    >
      <style>{`
        @keyframes sl-rise { from { opacity: 0; transform: translateY(14px); } to { opacity: 1; transform: translateY(0); } }
        .sl-rise { animation: sl-rise 0.45s cubic-bezier(0.2, 0.8, 0.2, 1); }
        @keyframes sl-fade { 0%, 70% { opacity: 1; } 100% { opacity: 0; } }
        .sl-fade { animation: sl-fade 4.5s forwards; }
        @keyframes sl-pulse { 0%, 100% { transform: scale(1); opacity: 0.8; } 50% { transform: scale(1.1); opacity: 1; } }
        .sl-pulse { animation: sl-pulse 2.4s ease-in-out infinite; }
        @keyframes sl-spin { to { transform: rotate(360deg); } }
        .sl-spin { animation: sl-spin 0.9s linear infinite; }
        @media (prefers-reduced-motion: reduce) { .sl-rise, .sl-fade, .sl-pulse, .sl-spin { animation: none; } }
        ::-webkit-scrollbar { display: none; }
      `}</style>
      <p style={{ fontFamily: SYS, fontSize: 12, fontWeight: 700, letterSpacing: "0.14em", color: "#9B968A", textTransform: "uppercase", marginBottom: 12 }}>
        Sideline · prototype v3 · your footage
      </p>
      <div
        className="flex flex-col overflow-hidden"
        style={{
          width: "min(390px, 100%)", height: "min(800px, calc(100vh - 90px))", minHeight: 640,
          borderRadius: 44, background: phase === "onboarding" ? BASE.paper : BASE.paper,
          boxShadow: "0 40px 90px -30px rgba(30,25,20,0.5), 0 0 0 10px #211E1A, 0 0 0 12px #3A362F",
        }}
      >
        <StatusBar />
        {screen}
        {phase === "app" && !flow && <TabBar tab={tab} setTab={setTab} badge={readyCount} ac={accent.a} />}
      </div>
      <p style={{ fontFamily: SYS, fontSize: 11.5, color: "#9B968A", marginTop: 14, textAlign: "center", maxWidth: 380, lineHeight: 1.5 }}>
        Scan-first interview · Mission chip on Today · tap a card to see why the employee made it · clear the stack to see Autopilot
      </p>
    </div>
  );
}
